import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Link } from 'react-router-dom';
import { ethers } from 'ethers';
import { deployTreasuryToken } from '../blockchain/treasuryTokenService';
import { deployReserveVault } from '../blockchain/treasuryVaultService';
import { deployCrowdsale } from '../blockchain/crowdsaleService';
import CreateTreasuryModal from '../components/CreateTreasuryModal';
import { mockTreasuries } from '../mocks/treasuries';
import type { Treasury } from '../mocks/treasuries';
import { mockProposals, Proposal } from '../mocks/proposals';
import { useDataMode } from '../contexts/DataModeContext';
import { getTokenBalance, isTreasuryToken, getTreasuryName, getTokenSupply } from '../utils/tokenUtils';

interface Notification {
  id: number;
  title: string;
  message: string;
  time: string;
  read: boolean;
}

interface DashboardProps {
  togglePreferences?: () => void;
  closeNotifications?: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({
  togglePreferences: togglePrefs = () => {},
  closeNotifications: closeNotifs = () => {}
}) => {
  const [showPreferences, setShowPreferences] = useState(false);
  const [showCreateTreasuryModal, setShowCreateTreasuryModal] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [isWalletConnected, setIsWalletConnected] = useState(false);
  const [deployedContracts, setDeployedContracts] = useState<{
    treasuryTokenAddress: string;
    treasuryVaultAddress: string;
    treasuryTokenSymbol: string;
    treasuryVaultSymbol: string;
  } | null>(null);
  const [treasuries, setTreasuries] = useState<Treasury[]>([]);
  const [proposals, setProposals] = useState<Proposal[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const { useLiveData } = useDataMode();
  const [userTreasuries, setUserTreasuries] = useState<Array<{
    name: string;
    vaultAddress: string;
    tokenAddress: string;
    tokenSymbol: string;
    userBalance: string;
    totalSupply: string;
  }>>([]);

  const [tokenBalances, setTokenBalances] = useState<{name: string, symbol: string, balance: string}[]>([]);

  // Mock token balances for development
  const mockTokenBalances = [
    { name: 'Ethereum', symbol: 'ETH', balance: '1.234' },
    { name: 'USD Coin', symbol: 'USDC', balance: '500.00' },
    { name: 'Dai Stablecoin', symbol: 'DAI', balance: '250.50' }
  ];

  // Mock user treasuries for development
  const mockUserTreasuries = [
    {
      name: 'Tech Startup Fund',
      vaultAddress: '0x742d35Cc6634C0532925a3b844Bc454e4438f44e',
      tokenAddress: '0x8ba1f109551bD4328030126452617686A9c1D4f4',
      tokenSymbol: 'TSF',
      userBalance: '1250.5000',
      totalSupply: '50000.00' // USDC balance in vault
    },
    {
      name: 'Green Energy Initiative',
      vaultAddress: '0x9c2d45Ee6634C0532925a3b844Bc454e4438f44f',
      tokenAddress: '0x1ba2f109551bD4328030126452617686A9c1D4f5',
      tokenSymbol: 'GEI',
      userBalance: '750.2500',
      totalSupply: '25000.00' // USDC balance in vault
    },
    {
      name: 'Community DAO Treasury',
      vaultAddress: '0x3d4e35Cc6634C0532925a3b844Bc454e4438f44g',
      tokenAddress: '0x2ca3f109551bD4328030126452617686A9c1D4f6',
      tokenSymbol: 'CDT',
      userBalance: '320.7500',
      totalSupply: '15000.00' // USDC balance in vault
    }
  ];

  // Common token addresses on Ethereum mainnet (you may want to make this configurable)
  const commonTokens = [
    { name: 'Ethereum', symbol: 'ETH', address: '0x0000000000000000000000000000000000000000' }, // Native ETH
    { name: 'USD Coin', symbol: 'USDC', address: '0xA0b86a33E6441e88C5F2712C3E9b74F5b8b6b8b8' }, // USDC
    { name: 'Dai Stablecoin', symbol: 'DAI', address: '0x6B175474E89094C44Da98b954EedeAC495271d0F' } // DAI
  ];

  // Fetch real token balances from wallet
  const fetchTokenBalances = async () => {
    if (!window.ethereum || !isWalletConnected) {
      return [];
    }

    try {
      const provider = new ethers.providers.Web3Provider(window.ethereum);
      const accounts = await provider.listAccounts();
      const userAddress = accounts[0];

      const balances = await Promise.all(
        commonTokens.map(async (token) => {
          try {
            let balance: string;
            
            if (token.address === '0x0000000000000000000000000000000000000000') {
              // Native ETH balance
              const ethBalance = await provider.getBalance(userAddress);
              balance = ethers.utils.formatEther(ethBalance);
            } else {
              // ERC20 token balance
              balance = await getTokenBalance(token.address, userAddress, provider);
              // Format the balance (assuming 18 decimals for simplicity)
              balance = ethers.utils.formatUnits(balance, 18);
            }

            return {
              name: token.name,
              symbol: token.symbol,
              balance: parseFloat(balance).toFixed(4)
            };
          } catch (error) {
            console.warn(`Failed to fetch balance for ${token.symbol}:`, error);
            return {
              name: token.name,
              symbol: token.symbol,
              balance: '0.0000'
            };
          }
        })
      );

      return balances;
    } catch (error) {
      console.error('Failed to fetch token balances:', error);
      return [];
    }
  };

  // Check wallet connection
  useEffect(() => {
    const checkWalletConnection = async () => {
      if (window.ethereum) {
        try {
          const accounts = await window.ethereum.request({ method: 'eth_accounts' });
          const connected = accounts.length > 0;
          setIsWalletConnected(connected);

          // Set mock data only if not connected
          if (!connected) {
            setTreasuries(mockTreasuries);
            setProposals([
              ...mockProposals,
              {
                id: 101,
                treasuryId: 1,
                title: 'Add New Liquidity Pool',
                description: 'Proposal to add a new liquidity pool for DAI stablecoin',
                createdDate: new Date().toISOString(),
                endDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString(),
                closedDate: null,
                status: 'active',
                votesFor: 3500,
                votesAgainst: 1200,
                hasVoted: true,
                voteType: 'accept',
                ownerApproved: true
              },
              {
                id: 102,
                treasuryId: 2,
                title: 'Update Protocol Fee',
                description: 'Proposal to reduce protocol fee from 0.3% to 0.25%',
                createdDate: new Date().toISOString(),
                endDate: new Date(Date.now() + 3 * 24 * 60 * 60 * 1000).toISOString(),
                closedDate: null,
                status: 'active',
                votesFor: 4200,
                votesAgainst: 3800,
                hasVoted: false,
                voteType: 'accept',
                ownerApproved: true
              }
            ]);
            setNotifications([
              {
                id: 1,
                title: 'New Proposal',
                message: 'Voting has started on Proposal #123',
                time: '2 hours ago',
                read: false
              },
              {
                id: 2,
                title: 'System Update',
                message: 'New features available in your dashboard',
                time: '1 day ago',
                read: false
              },
              {
                id: 3,
                title: 'Reminder',
                message: 'Don\'t forget to vote on the active proposals',
                time: '2 days ago',
                read: true
              }
            ]);
          } else {
            // Clear mock data when connected
            setTreasuries([]);
            setProposals([]);
            setNotifications([]);
          }
        } catch (error) {
          console.error('Error checking wallet connection:', error);
        }
      }
    };

    checkWalletConnection();

    // Listen for account changes
    if (window.ethereum) {
      window.ethereum.on('accountsChanged', (accounts: string[]) => {
        const connected = accounts.length > 0;
        setIsWalletConnected(connected);
        if (!connected) {
          setTreasuries(mockTreasuries);
          setProposals(mockProposals);
          setNotifications([
            {
              id: 1,
              title: 'New Proposal',
              message: 'Voting has started on Proposal #123',
              time: '2 hours ago',
              read: false
            },
            {
              id: 2,
              title: 'System Update',
              message: 'New features available in your dashboard',
              time: '1 day ago',
              read: false
            },
            {
              id: 3,
              title: 'Reminder',
              message: 'Don\'t forget to vote on the active proposals',
              time: '2 days ago',
              read: true
            }
          ]);
        } else {
          setTreasuries([]);
          setProposals([]);
          setNotifications([]);
        }
      });
    }

    return () => {
      if (window.ethereum) {
        window.ethereum.removeListener('accountsChanged', checkWalletConnection);
      }
    };
  }, []);

  // Update token balances based on data mode and wallet connection
  useEffect(() => {
    const updateTokenBalances = async () => {
      if (useLiveData && isWalletConnected) {
        // Fetch real token balances from wallet
        const realBalances = await fetchTokenBalances();
        setTokenBalances(realBalances.length > 0 ? realBalances : mockTokenBalances);
      } else {
        // Use mock data
        setTokenBalances(mockTokenBalances);
      }
    };

    updateTokenBalances();
  }, [useLiveData, isWalletConnected]);

  // Fetch user treasuries (treasuries where user has tokens)
  useEffect(() => {
    const fetchUserTreasuries = async () => {
      if (!useLiveData) {
        // In mock mode, show mock user treasuries
        setUserTreasuries(mockUserTreasuries);
        return;
      }

      if (!isWalletConnected || !window.ethereum) {
        // No wallet connected, show empty
        setUserTreasuries([]);
        return;
      }

      try {
        const provider = new ethers.providers.Web3Provider(window.ethereum);
        const accounts = await provider.listAccounts();
        const userAddress = accounts[0];

        // Fetch USDC contract address
        const usdcResponse = await fetch('http://localhost:4000/api/contract-addresses/Ethereum%20Sepolia(USDC)');
        const usdcData = await usdcResponse.json();
        const usdcAddress = usdcData.contractAddress?.address;

        if (!usdcAddress) {
          console.warn('USDC contract address not found');
          setUserTreasuries([]);
          return;
        }

        // Fetch deployed treasuries from API
        const response = await fetch('http://localhost:4000/api/deployed-treasuries?page=1&limit=50');
        const data = await response.json();

        // Filter treasuries where user has tokens
        const userTreasuriesData = [];

        for (const treasury of data.treasuries) {
          try {
            // Check if the token is a treasury token
            const isTreasuryTokenResult = await isTreasuryToken(treasury.tokenAddress, provider);
            
            if (isTreasuryTokenResult) {
              // Check user's balance
              const balance = await getTokenBalance(treasury.tokenAddress, userAddress, provider);
              
              if (parseFloat(balance) > 0) {
                // Get vault address from token contract's treasuryName()
                const vaultAddress = await getTreasuryName(treasury.tokenAddress, provider);
                
                if (vaultAddress && vaultAddress !== '0x0000000000000000000000000000000000000000') {
                  // Get treasury display name from vault contract's treasuryName()
                  let treasuryDisplayName = treasury.name; // fallback
                  try {
                    treasuryDisplayName = await getTreasuryName(vaultAddress, provider);
                    if (!treasuryDisplayName || treasuryDisplayName === '0x0000000000000000000000000000000000000000') {
                      treasuryDisplayName = treasury.name; // fallback to API name
                    }
                  } catch (error) {
                    console.warn(`Could not get treasury name from vault ${vaultAddress}, using API name`);
                  }
                  
                  // Get USDC balance of the vault
                  const vaultUsdcBalance = await getTokenBalance(usdcAddress, vaultAddress, provider);
                  
                  // Format balance and USDC balance (USDC has 6 decimals)
                  const formattedBalance = ethers.utils.formatUnits(balance, 18);
                  const formattedUsdcBalance = ethers.utils.formatUnits(vaultUsdcBalance, 6);
                  
                  userTreasuriesData.push({
                    name: treasuryDisplayName,
                    vaultAddress: vaultAddress,
                    tokenAddress: treasury.tokenAddress,
                    tokenSymbol: treasury.tokenSymbol,
                    userBalance: parseFloat(formattedBalance).toFixed(4),
                    totalSupply: parseFloat(formattedUsdcBalance).toFixed(2)
                  });
                }
              }
            }
          } catch (error) {
            console.warn(`Error checking treasury ${treasury.name}:`, error);
          }
        }

        setUserTreasuries(userTreasuriesData);
      } catch (error) {
        console.error('Error fetching user treasuries:', error);
        setUserTreasuries([]);
      }
    };

    fetchUserTreasuries();
  }, [useLiveData, isWalletConnected]);

  // Get accepted proposals that the user has voted on
  const acceptedProposals = useMemo(() => 
    proposals
      .filter((proposal: Proposal) => 
        proposal.hasVoted && 
        proposal.voteType === 'accept' && 
        proposal.status === 'active'
      )
      .map(proposal => ({
        ...proposal,
        votePercentage: Math.round((proposal.votesFor / (proposal.votesFor + proposal.votesAgainst)) * 100)
      })),
    [proposals]
  );

  const handleDeploy = async (deployParams: {
    name: string;
    symbol: string;
    resName: string;
    tokenName: string;
    tokenSymbol: string;
  }): Promise<{
    treasuryTokenAddress: string;
    reserveVaultAddress: string;
  }> => {
    try {
      const provider = new ethers.providers.Web3Provider(window.ethereum);
      const signer = provider.getSigner();
      // 1. Deploy TreasuryToken contract
      const treasuryTokenAddress = await deployTreasuryToken(
        signer,
        deployParams.name,
        deployParams.symbol
      );
      // 2. Deploy the treasury vault contract
      const { reserveVaultAddress } = await deployReserveVault(
        signer,
        deployParams.resName,
        treasuryTokenAddress,
        deployParams.tokenName,
        deployParams.tokenSymbol
      );
      // 3. Initialize the token with the treasury vault address
      const tokenContract = new ethers.Contract(
        treasuryTokenAddress,
        [
          'function initTreasury(address newOwner) external',
          'function addAuth(address authUser) external'
        ],
        signer
      );
      await tokenContract.initTreasury(reserveVaultAddress);
      // 4. Set the deployed contracts data in state and show the crowdsale modal
      const deploymentData = {
        treasuryTokenAddress,
        treasuryVaultAddress: reserveVaultAddress,
        treasuryTokenSymbol: deployParams.symbol,
        treasuryVaultSymbol: deployParams.tokenSymbol
      };
      // 5. Update UI with the new treasury
      const newTreasury: Treasury = {
        id: Math.max(0, ...treasuries.map((r: Treasury) => r.id)) + 1,
        treasuryName: deployParams.resName,
        contractAddress: reserveVaultAddress,
        tokenSymbol: deployParams.symbol,
        proposalTokenSymbol: 'p' + deployParams.symbol,
        totalValueLocked: '$0',
        apy: '0%',
        isJoined: false,
        openProposals: 0,
        closedProposals: 0,
        totalMembers: 1,
        ownerAddress: await signer.getAddress(),
        authorizedUsers: [],
        treasuryTokenBalance: '0',
        proposalTokenBalance: '0',
        yourStake: '0'
      };
      setTreasuries([...treasuries, newTreasury]);
      setDeployedContracts(deploymentData);
      setShowCreateTreasuryModal(false);
      setNotifications((prev: Notification[]) => [
        {
          id: Date.now(),
          title: 'Treasury Created',
          message: `Treasury "${deployParams.resName}" deployed at ${reserveVaultAddress}`,
          time: new Date().toLocaleTimeString(),
          read: false
        },
        ...prev
      ]);
      return {
        treasuryTokenAddress,
        reserveVaultAddress: reserveVaultAddress
      };
    } catch (error) {
      console.error('Error deploying contracts:', error);
      throw error;
    }
  };
  
  const handleLaunchCrowdsale = useCallback(async (ratio: number): Promise<void> => {
    try {
      if (!deployedContracts) return;
      
      // In a real app, you would deploy the crowdsale contract here
      console.log('Launching crowdsale with ratio:', ratio);
      console.log('Token address:', deployedContracts.treasuryTokenAddress);
      console.log('Vault address:', deployedContracts.treasuryVaultAddress);
      
      // Mock deployment - in a real app, this would be an actual contract deployment
      await new Promise(resolve => setTimeout(resolve, 2000));
      
      // Update UI or show success message
      setNotifications((prev: Notification[]) => [
        {
          id: Date.now(),
          title: 'Crowdsale Launched',
          message: `Crowdsale launched with ratio ${ratio} for treasury`,
          time: new Date().toLocaleTimeString(),
          read: false
        },
        ...prev
      ]);
      
      // Close the modal
    } catch (error) {
      console.error('Error launching crowdsale:', error);
      // Show error notification
      setNotifications((prev: Notification[]) => [
        {
          id: Date.now(),
          title: 'Crowdsale Launch Failed',
          message: 'Failed to launch crowdsale. Please try again.',
          time: new Date().toLocaleTimeString(),
          read: false
        },
        ...prev
      ]);
      throw error;
    }
  }, [deployedContracts]);

  const closeNotifications = useCallback((): void => {
    setShowNotifications(false);
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      const target = event.target as HTMLElement;
      if (showNotifications && !target.closest('.notifications-widget') && !target.closest('.notifications-btn')) {
        closeNotifications();
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [showNotifications, closeNotifications]);

  const togglePreferences = useCallback((): void => {
    setShowPreferences((prev: boolean) => !prev);
  }, []);

  const toggleNotifications = useCallback((): void => {
    setShowNotifications((prev: boolean) => {
      if (!prev) {
        setNotifications((currentNotifications: Notification[]) => 
          currentNotifications.map((notification: Notification) => ({
            ...notification,
            read: true
          }))
        );
      }
      return !prev;
    });
  }, []);

  return (
    <div className="dashboard-container">
      <main className="dashboard-content">
        <div className="dashboard-header">
          <h1>Dashboard</h1>
          <div className="dashboard-actions" style={{ display: 'flex', gap: '10px' }}>
            <Link to="/treasuries/find" className="btn primary">
              Find a Treasury
            </Link>
          </div>
        </div>
        
        <div className="dashboard-grid">
          {/* Balance Card */}
          <div className="widget balance-card">
            <h3>Wallet Tokens</h3>
            <div className="token-list">
              {useLiveData && !isWalletConnected ? (
                <div className="token-item" style={{ justifyContent: 'center', fontStyle: 'italic', color: '#666' }}>
                  Connect wallet to view token balances
                </div>
              ) : (
                tokenBalances.map((token, index) => (
                  <div key={index} className="token-item">
                    <span className="token-name">{token.name} ({token.symbol})</span>
                    <span className="token-balance">{token.balance}</span>
                  </div>
                ))
              )}
            </div>
          </div>
          
          {/* Quick Actions */}
          <div className="widget quick-actions">
            <h3>Quick Actions</h3>
            <div className="action-buttons">
              <Link to="/treasuries#joined" className="btn secondary">Joined Treasuries</Link>
              <button 
                className="btn secondary" 
                onClick={() => setShowCreateTreasuryModal(true)}
              >
                Create A Treasury
              </button>
              <button 
                className="btn secondary notifications-btn"
                onClick={toggleNotifications}
              >
                Notifications
                {notifications.some(n => !n.read) && (
                  <span className="notification-badge"></span>
                )}
              </button>
              <button className="btn secondary" onClick={togglePreferences}>
                Preferences
              </button>
            </div>
          </div>
          
          {/* Your Treasuries */}
          <div className="widget your-treasuries">
            <style jsx>{`
              .your-treasuries .treasury-list {
                margin-top: 1rem;
              }
              
              .treasury-item {
                display: flex;
                padding: 0.75rem 0;
                border-bottom: 1px solid #edf2f7;
                align-items: center;
                min-width: 0; /* Allow flex items to shrink below content size */
              }
              
              .treasury-item:last-child {
                border-bottom: none;
              }
              
              .treasury-icon {
                width: 2rem;
                height: 2rem;
                border-radius: 50%;
                display: flex;
                align-items: center;
                justify-content: center;
                margin-right: 0.75rem;
                flex-shrink: 0;
                background-color: #4f46e5;
                color: white;
                font-weight: bold;
                font-size: 0.875rem;
              }
              
              .treasury-details {
                flex: 1;
                min-width: 0;
                overflow: hidden; /* Prevent overflow */
              }
              
              .treasury-name {
                font-weight: 600;
                color: #1a202c;
                margin-bottom: 0.25rem;
                white-space: nowrap;
                overflow: hidden;
                text-overflow: ellipsis;
              }
              
              .treasury-address {
                color: #6b7280;
                font-size: 0.75rem;
                font-family: monospace;
                white-space: nowrap;
                overflow: hidden;
                text-overflow: ellipsis;
              }
              
              .treasury-balance {
                font-weight: 500;
                color: #10b981;
                font-size: 0.875rem;
                flex-shrink: 0;
                margin-left: 0.75rem;
                white-space: nowrap;
              }
              
              .no-treasuries {
                text-align: center;
                padding: 2rem;
                color: #9ca3af;
                font-style: italic;
              }
              
              /* Scrollbar styling */
              .treasury-list::-webkit-scrollbar {
                width: 6px;
              }
              
              .treasury-list::-webkit-scrollbar-track {
                background: #f1f1f1;
                border-radius: 3px;
              }
              
              .treasury-list::-webkit-scrollbar-thumb {
                background: #cbd5e0;
                border-radius: 3px;
              }
              
              .treasury-list::-webkit-scrollbar-thumb:hover {
                background: #a0aec0;
              }
            `}</style>
            <h3>Your Treasuries</h3>
            <div className="treasury-list" style={{ maxHeight: '400px', overflowY: 'auto' }}>
              {userTreasuries.length === 0 ? (
                <div className="no-treasuries">
                  {useLiveData && !isWalletConnected 
                    ? 'Connect wallet to view your treasuries' 
                    : 'No treasuries found'
                  }
                </div>
              ) : (
                userTreasuries.map((treasury, index) => (
                  <div key={index} className="treasury-item">
                    <div className="treasury-icon">
                      {treasury.name.charAt(0).toUpperCase()}
                    </div>
                    <div className="treasury-details">
                      <div className="treasury-name">{treasury.name}</div>
                      <div className="treasury-address">
                        {treasury.vaultAddress.substring(0, 6)}...{treasury.vaultAddress.substring(treasury.vaultAddress.length - 4)}
                      </div>
                    </div>
                    <div className="treasury-balance">
                      {treasury.totalSupply} USDC
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
          
          {/* Accepted Proposals Activity */}
          <div className="widget accepted-proposals">
            <h3>Accepted Proposals</h3>
            <div className="proposals-list">
              {acceptedProposals.length === 0 ? (
                <div className="no-proposals">
                  <p>No accepted proposals yet</p>
                  <p className="small">Vote on proposals to see them here</p>
                </div>
              ) : (
                acceptedProposals.map(proposal => {
                  const treasury = treasuries.find(r => r.id === proposal.treasuryId);
                  const treasuryName = treasury ? treasury.treasuryName : 'Unknown Treasury';
                  
                  return (
                    <Link 
                      key={proposal.id} 
                      to={`/treasuries/${proposal.treasuryId}/proposals`}
                      className="proposal-item"
                      style={{ textDecoration: 'none', display: 'block' }}
                    >
                      <div className="proposal-content">
                        <div>
                          <div className="proposal-title">{proposal.title}</div>
                          <div className="proposal-treasury" style={{ fontSize: '0.85rem', color: '#6b7280', marginTop: '0.25rem' }}>
                            {treasuryName}
                          </div>
                        </div>
                        <div className="proposal-details">
                          <div className="proposal-status">
                            <span className={`status-badge ${proposal.status}`}>
                              {proposal.status.charAt(0).toUpperCase() + proposal.status.slice(1)}
                            </span>
                          </div>
                          <div className="proposal-stats">
                            <div className="stat-item">
                              <div className="stat-label">24Hr</div>
                              <div className="stat-value positive">2.5%</div>
                            </div>
                            <div className="stat-item">
                              <div className="stat-label">1M</div>
                              <div className="stat-value negative">-1.2%</div>
                            </div>
                            <div className="stat-item">
                              <div className="stat-label">Days Left</div>
                              <div className="stat-value">
                                {proposal.endDate ? Math.ceil((Date.parse(proposal.endDate) - Date.now()) / (1000 * 60 * 60 * 24)) : 'N/A'}
                              </div>
                            </div>
                          </div>
                        </div>
                      </div>
                    </Link>
                  );
                })
              )}
            </div>
          </div>
          
          {/* Active Loans */}
          <div className="widget active-loans">
            <h3>Active Treasuries</h3>
            <div className="loans-count">0</div>
            <div className="loans-amount">$0.00</div>
          </div>
          

        </div>
      </main>
      
      <CreateTreasuryModal 
        isOpen={showCreateTreasuryModal}
        onClose={() => setShowCreateTreasuryModal(false)}
        onDeploy={handleDeploy}
      />
      
      {/* Notifications Panel */}
      <div className={`overlay ${showNotifications ? 'visible' : ''}`} onClick={closeNotifications}></div>
      <div className={`notifications-widget ${showNotifications ? 'open' : ''}`}>
        <div className="notifications-header">
          <h3>Notifications</h3>
          <button className="close-notifications" onClick={closeNotifications}>
            &times;
          </button>
        </div>
        <div className="notifications-list">
          {notifications.length === 0 ? (
            <div className="notification-item">
              <p>No new notifications</p>
            </div>
          ) : (
            notifications.map(notification => (
              <div key={notification.id} className={`notification-item ${!notification.read ? 'unread' : ''}`}>
                <h4>{notification.title}</h4>
                <p>{notification.message}</p>
                <div className="notification-time">{notification.time}</div>
              </div>
            ))
          )}
        </div>
      </div>

      {showPreferences && (
        <div className="modal-overlay" onClick={togglePreferences}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>Preferences</h3>
              <button className="close-button" onClick={togglePreferences}>&times;</button>
            </div>
            <div className="modal-body">
              <div className="preference-item">
                <label>
                  <input type="checkbox" /> Dark Mode
                </label>
              </div>
              <div className="preference-item">
                <label>
                  <input type="checkbox" /> Email Notifications
                </label>
              </div>
              <div className="preference-item">
                <label>
                  <input type="checkbox" /> Push Notifications
                </label>
              </div>
              <div className="modal-actions">
                <button className="btn primary" onClick={togglePreferences}>Save</button>
                <button className="btn secondary" onClick={togglePreferences}>Cancel</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;
